  2→import React, { useState, useEffect } from 'react';
  3→import { User } from '../types';
  4→import { Check, Download, ArrowLeft, ShieldCheck, LayoutList, History, FileText, Zap, Database, Fuel, Droplet, CreditCard, Star, Loader2, Sparkles, ArrowUpRight } from 'lucide-react';
  5→import jsPDF from 'jspdf';
  6→
  7→interface PlanProps {
  8→  onBack: () => void;
  9→  user: User | null;
 10→  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
 11→  initialTab?: 'my-plan' | 'pricing' | 'billing';
 12→}
 13→
 14→const Plan: React.FC<PlanProps> = ({ onBack, user, onUpgrade, initialTab = 'my-plan' }) => {
 15→  const [activeTab, setActiveTab] = useState<'my-plan' | 'pricing' | 'billing'>(initialTab);
 16→  const [isProcessing, setIsProcessing] = useState(false);
 17→  const [upgradeModal, setUpgradeModal] = useState<{ planId: string; planName: string; newPrice: number } | null>(null);
 18→  const [paymentStep, setPaymentStep] = useState<'recap' | 'payment' | 'success'>('recap');
 19→  const [paidAmount, setPaidAmount] = useState(0);
 20→  const [paymentHistory, setPaymentHistory] = useState([
 21→    { id: 'INV-2024-003', date: '01/03/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 22→    { id: 'INV-2024-002', date: '01/02/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 23→    { id: 'INV-2024-001', date: '15/01/2024', amount: 49.00, desc: 'Pack GTO Gas (La Pompe)', status: 'Payé' },
 24→  ]);
 25→
 26→  useEffect(() => {
 27→    setActiveTab(initialTab);
 28→  }, [initialTab]);
 29→
 30→  const plans = [
 31→    {
 32→      id: 'free',
 33→      name: 'Starter',
 34→      price: 29,
 35→      period: '/mois',
 36→      icon: <Droplet size={24} />,
 37→      features: ['1 Projet Actif / mois', 'Audit manuel', 'Support communauté'],
 38→      cta: 'Plan Actuel',
 39→      current: user?.plan === 'free'
 40→    },
 41→    {
 42→      id: 'pro',
 43→      name: 'Pro',
 44→      price: 89,
 45→      period: '/mois',
 46→      icon: <Fuel size={24} />,
 47→      popular: true,
 48→      features: ['Indexation IA', '3 Projets Actifs / mois', 'Monitoring Continu', 'Support Prioritaire', 'API Access (Beta)', 'Rapports PDF marque blanche'],
 49→      cta: 'Passer Pro',
 50→      current: user?.plan === 'pro'
 51→    },
 52→    {
 53→      id: 'enterprise',
 54→      name: 'Agency',
 55→      price: 299,
 56→      period: '/mois',
 57→      icon: <Database size={24} />,
 58→      features: ['Indexation IA', 'Projets illimités', 'Dedicated Account Manager', 'API Full Access', 'SSO & Sécurité avancée', 'Formation AEO équipe'],
 59→      cta: 'Passer Agency',
 60→      current: user?.plan === 'enterprise'
 61→    }
 62→  ];
 63→
 64→  const currentPlanPrice = user?.plan === 'enterprise' ? 299 : user?.plan === 'pro' ? 89 : 29;
 65→  const currentPlanName = user?.plan === 'enterprise' ? 'Agency' : user?.plan === 'pro' ? 'Pro' : 'Starter';
 66→
 67→  const handleUpgradeClick = (planId: string) => {
 68→    const targetPlan = plans.find(p => p.id === planId);
