 70→    setUpgradeModal({ planId, planName: targetPlan.name, newPrice: targetPlan.price });
 71→  };
 72→
 73→  const handleConfirmUpgrade = () => {
 74→    if (!upgradeModal) return;
 75→    setPaymentStep('payment');
 76→  };
 77→
 78→  const handleProcessPayment = () => {
 79→    if (!upgradeModal) return;
 80→    setIsProcessing(true);
 81→    setTimeout(() => {
 82→      const amountPaid = upgradeModal.newPrice - currentPlanPrice;
 83→      const now = new Date();
 84→      const dateStr = now.toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' });
 85→      const invoiceNum = `INV-${now.getFullYear()}-${String(paymentHistory.length + 1).padStart(3, '0')}`;
 86→      const newInvoice = {
 87→        id: invoiceNum,
 88→        date: dateStr,
 89→        amount: amountPaid,
 90→        desc: `Upgrade ${currentPlanName} → ${upgradeModal.planName} (Prorata)`,
 91→        status: 'Payé',
 92→      };
 93→      setPaymentHistory(prev => [newInvoice, ...prev]);
 94→      setPaidAmount(amountPaid);
 95→      onUpgrade(upgradeModal.planId as any);
 96→      setIsProcessing(false);
 97→      setPaymentStep('success');
 98→    }, 2500);
 99→  };
100→
101→  const handleCloseUpgradeModal = () => {
