150→
151→    doc.setFont("helvetica", "bold");
152→    doc.setFontSize(12);
153→    doc.text("Total TTC :", 130, 117);
154→    doc.text(`${payment.amount.toFixed(2)} €`, 160, 117);
155→
156→    doc.setFontSize(8);
